            i++;
            continue;
        }
        // The number of elements we can take before activeCount reaches currentLimit
        const take = currentLimit - activeCount;
        const end = Math.min(i + take, n);
        // Sum the values from i to end-1
        for (let j = i; j < end; j++) {
            if (activeCount < limit[indices[j]]) {
                total += value[indices[j]];
                activeCount++;
            } else {
                break;
            }
        }
        // After adding, any elements with limit <= activeCount become inactive
        // So we need to skip elements where limit[j] <= activeCount
        while (i < n && limit[indices[i]] <= activeCount) {
            i++;
        }
    }

    return total;
}
